import{_ as t,c as i,o as a,a1 as o}from"./chunks/framework.DDNAyvCW.js";const u=JSON.parse('{"title":"Mobile Quick Start","description":"","frontmatter":{},"headers":[],"relativePath":"docs/mobile/quickstart/index.md","filePath":"docs/mobile/quickstart/index.md"}'),n={name:"docs/mobile/quickstart/index.md"};function l(r,e,s,d,c,h){return a(),i("div",null,e[0]||(e[0]=[o('<h1 id="mobile-quick-start" tabindex="-1">Mobile Quick Start <a class="header-anchor" href="#mobile-quick-start" aria-label="Permalink to &quot;Mobile Quick Start&quot;">â€‹</a></h1><p>This guide walks you through installing the mobile app, signing in, adding your first host, opening an SSH session, and trying AI features.</p><h2 id="step-1-install-the-app" tabindex="-1">Step 1: Install the App <a class="header-anchor" href="#step-1-install-the-app" aria-label="Permalink to &quot;Step 1: Install the App&quot;">â€‹</a></h2><h3 id="ios" tabindex="-1">iOS <a class="header-anchor" href="#ios" aria-label="Permalink to &quot;iOS&quot;">â€‹</a></h3><ol><li>Open <a href="https://apps.apple.com/app/6754307456" target="_blank" rel="noreferrer">App Store</a></li><li>Search for and install Chaterm</li><li>Complete the permission prompts when you launch it for the first time</li></ol><h3 id="android" tabindex="-1">Android <a class="header-anchor" href="#android" aria-label="Permalink to &quot;Android&quot;">â€‹</a></h3><ol><li>Open <a href="https://play.google.com/store/apps/details?id=com.intsig.chaterm.global" target="_blank" rel="noreferrer">Google Play</a></li><li>Search for and install Chaterm</li><li>Complete the permission prompts when you launch it for the first time</li></ol><div class="tip custom-block"><p class="custom-block-title">Tip</p><p>If you want data sync and full AI features, it is best to sign in before you start using the app.</p></div><h2 id="step-2-sign-in" tabindex="-1">Step 2: Sign In <a class="header-anchor" href="#step-2-sign-in" aria-label="Permalink to &quot;Step 2: Sign In&quot;">â€‹</a></h2><p>Chaterm mobile supports both full sign-in usage and browsing first before finishing sign-in later.</p><ul><li>Email verification code sign-in</li><li>Username and password sign-in</li><li>Third-party sign-in, depending on the options currently available in the app</li></ul><h2 id="step-3-add-your-first-host" tabindex="-1">Step 3: Add Your First Host <a class="header-anchor" href="#step-3-add-your-first-host" aria-label="Permalink to &quot;Step 3: Add Your First Host&quot;">â€‹</a></h2><ol><li>Open the Assets page</li><li>Enter Direct Connections and tap the <code>+</code> button in the lower-right corner</li><li>Choose <code>New</code></li><li>Fill in the host label, IP address, port, username, and other details</li><li>Select password authentication or key authentication</li><li>Tap <code>Save</code></li></ol><p>If you have enabled data sync on desktop, your asset data is encrypted and synced to mobile automatically.</p><p>For more details, see <a href="/docs/mobile/assets/">Asset Management</a>.</p><h2 id="step-4-open-an-ssh-connection" tabindex="-1">Step 4: Open an SSH Connection <a class="header-anchor" href="#step-4-open-an-ssh-connection" aria-label="Permalink to &quot;Step 4: Open an SSH Connection&quot;">â€‹</a></h2><ol><li>Tap the target host card in the asset list</li><li>Chaterm automatically creates the SSH connection</li><li>After the connection succeeds, you enter the terminal screen</li></ol><p>Common actions:</p><ul><li>Tap a host card to connect directly</li><li>Long-press a card to edit, favorite, or delete it</li><li>Use search to quickly filter by host name, IP, username, or group</li></ul><h2 id="step-5-start-using-ai" tabindex="-1">Step 5: Start Using AI <a class="header-anchor" href="#step-5-start-using-ai" aria-label="Permalink to &quot;Step 5: Start Using AI&quot;">â€‹</a></h2><p>Mobile provides two main interaction modes:</p><ul><li><code>Term</code> mode: directly runs the command you enter</li><li><code>Chat</code> mode: lets AI understand the request and suggest commands or actions</li></ul><p>Basic flow:</p><ol><li>Open the AI dialog page</li><li>Connect to a target host or select a model</li><li>Switch modes from the selector at the bottom of the input box</li><li>Enter a question or command, or use voice input</li><li>Review the execution result or the AI response</li></ol><p>For more details, see <a href="/docs/mobile/ai-agent/">AI Dialog</a>.</p><h2 id="recommended-first-run" tabindex="-1">Recommended First Run <a class="header-anchor" href="#recommended-first-run" aria-label="Permalink to &quot;Recommended First Run&quot;">â€‹</a></h2><ol><li>Add a test host</li><li>Start one SSH session</li><li>Run <code>pwd</code> or <code>uname -a</code> in <code>Term</code> mode</li><li>Switch to <code>Chat</code> mode and ask one Linux command question</li><li>Open Profile and configure theme, language, and AI preferences</li></ol>',27)]))}const m=t(n,[["render",l]]);export{u as __pageData,m as default};
